steps.command:
eval "() => { const cm = document.querySelector('.CodeMirror').CodeMirror; const existing = cm.getValue(); const newScript = existing + '
<!-- Hide Place Request button on catalog items 604, 607 -->
<script>
(function() {
  var style = document.createElement("style");
  style.textContent = ".place-request-footer, .place-request-btn, input.place-request-btn { display: none !important; }";

  function check() {
    var url = window.location.href;
    var target = url.indexOf("/support/catalog/items/604") !== -1 || url.indexOf("/support/catalog/items/607") !== -1;
    if (target && !style.parentNode) document.head.appendChild(style);
    if (!target && style.parentNode) style.parentNode.removeChild(style);
  }

  check();
  setInterval(check, 500);
})();
</script>'; cm.setValue(newScript); cm.refresh(); return cm.getValue(); }"

steps.function_template:
(existing_content, item_ids, css_selectors, element_description) => { const url_checks = item_ids.map(id => `url.indexOf("/support/catalog/items/${id}") !== -1`).join(' || '); const script = `
<!-- Hide ${element_description} on catalog items ${item_ids.join(', ')} -->
<script>
(function() {
  var style = document.createElement("style");
  style.textContent = "${css_selectors} { display: none !important; }";

  function check() {
    var url = window.location.href;
    var target = ${url_checks};
    if (target && !style.parentNode) document.head.appendChild(style);
    if (!target && style.parentNode) style.parentNode.removeChild(style);
  }

  check();
  setInterval(check, 500);
})();
</script>`; const cm = document.querySelector('.CodeMirror').CodeMirror; cm.setValue(existing_content + script); cm.refresh(); return cm.getValue(); }
